// Simulación de notificación al cliente por email
const body = $input.first().json.body || $input.first().json;

const mensaje = {
  para: body.usuario_email,
  nombre: body.usuario_nombre,
  asunto: `Pedido #${body.pedido_id} — En proceso de armado`,
  cuerpo: [
    `Hola ${body.usuario_nombre},`,
    ``,
    `Tu pedido #${body.pedido_id} fue validado y está en proceso de armado.`,
    `Estado: ${body.estado}`,
    `Total: $${body.total}`,
    ``,
    `Te avisaremos cuando esté listo para retirar.`,
    ``,
    `Óptica Demo`
  ].join('\n')
};

console.log('[ÓPTICA DEMO] Email simulado enviado:');
console.log(JSON.stringify(mensaje, null, 2));

return [{
  json: {
    ok: true,
    tipo: 'EMAIL_SIMULADO',
    pedido_id: body.pedido_id,
    destinatario: body.usuario_email,
    timestamp: new Date().toISOString()
  }
}];
